            ("max_cookies_per_domain", max_cookies_per_domain),
        ):
            if value is not None and (
                not isinstance(value, int) or isinstance(value, bool)
            ):
                raise TypeError(f"{name} must be an int or None")
            if value is not None and value < 0:
